VALUES
  ('dietitian-moex-08974', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某研究者若要編制一份國小教師的健康食品認知問卷，為符合問卷編制的要求，其實施步驟應如何進行？', '["問卷預試", "專家效度", "問卷信度", "題目設計"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08975', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '問卷中的題目，依其待答方式的不同，可分成封閉式問題（close-endedquestions）或開放式問題（open-ended questions），下列何者是封閉式問題的特性？', '["資料難以量化和解釋", "有標準的答案，便於比較每個人的觀點", "在未了解某現象的有關特徵時，可利用此種問題", "填答時需花較多的時間，易遭拒答"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08976', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據營養師法的規定，營養師需定期更新其執業執照，下列有關執照更新的年限與應接受繼續教育課程的 積分，何者正確？', '["6年，180點", "6年，150點", "5年，150點", "5年，120點"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08977', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '鐵耗損分成三階段，其中有關第二階段缺鐵期的敘述，何者錯誤？', '["血紅素合成量減少，已呈現小血球性貧血症狀", "血液中運送之鐵量減少，造血組織獲鐵量低於正常", "鐵蛋白濃度低於12μg/L", "運鐵蛋白飽和度 <15%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08978', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '進行各種體重控制計畫的成效評估時，若決策者比較不同的體重控制計畫中，以每降低一公斤體重所花費 的經費來進行評估，此種分析方法屬於下列何者？', '["成本決策分析", "成本利益分析", "成本效益分析", "損益平衡分析"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08979', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據1999-2000年台灣地區老人營養健康狀況調查分析，台灣地區65歲以上老人慢性病的盛行率，以何者 為最高？', '["高尿酸", "高三酸甘油脂血症", "糖尿病", "高血壓"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08980', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '藉由生化檢測可了解潛在的營養素缺乏狀況。下列有關生化檢測情形的敘述，何者正確？', '["紅 血球 轉酮酶（erythrocytetransketolase）活性＞1.20，表示維生素B 正常 1", "色氨酸負荷試驗，可了解維生素B 的缺乏情形 2", "測尿中的Formiminoglutamate（FIGLU）之排泄量，可反映葉酸營養狀況", "SchillingTest可用來評估維生素B 的吸收能力 6"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08981', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '由下列何者所獲得的營養素可獲量（Availability）與罹患疾病的相關性資訊，最容易用來與他國作比較？', '["24小時飲食回憶法", "食物平衡表", "飲食記錄法", "家戶食物盤存秤量法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08982', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '推行低脂飲食的營養教育時，先分析學習者的情況，再據以撰寫此計畫的目標，並選擇適合的媒體與教材， 教導學習者有關的知識，並要求參與者落實實施 DASH飲食，最後進行評鑑與修正。此種營養教育模式最 符合下列何者？', '["HealthBeliefModel", "ASSUREModel", "CommunityOrganizationModel", "SocialMarketingModel"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08983', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一種飲食評估方法之敘述最正確？', '["飲食稱重盤存記錄法可了解國家長期飲食趨勢的變化", "飲食攝取頻率法能正確的評估三大營養素攝取量", "24小時回憶法不能得知個人營養素的攝取量", "飲食記錄法最常被用來驗證膳食頻率問卷的效度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
